import{_ as a,c as s,o as e,a1 as r}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"初回起動: データディレクトリをマスター | Antigravity Tools","description":"Antigravity Tools のデータディレクトリの位置とログ管理を学びます。設定ページでデータディレクトリを開く、ログをクリア、トレイ実行と自動起動、2 種類の自動起動の区別をマスターします。","frontmatter":{"title":"初回起動: データディレクトリをマスター | Antigravity Tools","sidebarTitle":"データディレクトリを見つける","subtitle":"初回起動必須：データディレクトリ、ログ、トレイと自動起動","description":"Antigravity Tools のデータディレクトリの位置とログ管理を学びます。設定ページでデータディレクトリを開く、ログをクリア、トレイ実行と自動起動、2 種類の自動起動の区別をマスターします。","tags":["初回起動","データディレクトリ","ログ","トレイ","自動起動"],"prerequisite":["start-getting-started","start-installation"],"order":3},"headers":[],"relativePath":"ja/lbjlaq/Antigravity-Manager/start/first-run-data/index.md","filePath":"ja/lbjlaq/Antigravity-Manager/start/first-run-data/index.md"}'),i={name:"ja/lbjlaq/Antigravity-Manager/start/first-run-data/index.md"};function o(d,t,l,n,c,h){return e(),s("div",null,[...t[0]||(t[0]=[r(`<h1 id="初回起動必須-データディレクトリ、ログ、トレイと自動起動" tabindex="-1">初回起動必須：データディレクトリ、ログ、トレイと自動起動 <a class="header-anchor" href="#初回起動必須-データディレクトリ、ログ、トレイと自動起動" aria-label="Permalink to &quot;初回起動必須：データディレクトリ、ログ、トレイと自動起動&quot;">​</a></h1><p>Antigravity Tools の多くの「魔法のように見える」能力（アカウントプール、クォータ、監視、統計、バックグラウンド実行）は、最終的に 2 つのものに帰着します：<strong>データディレクトリ</strong>と<strong>ログ</strong>。最初にこれら 2 つを明確にしておけば、後のトラブルシューティングで多くの時間を節約できます。</p><h2 id="データディレクトリとは" tabindex="-1">データディレクトリとは？ <a class="header-anchor" href="#データディレクトリとは" aria-label="Permalink to &quot;データディレクトリとは？&quot;">​</a></h2><p><strong>データディレクトリ</strong>は Antigravity Tools がローカルマシンで状態を保存するフォルダです：アカウント JSON、クォータ関連ファイル、ログファイル、Token Stats/Proxy Monitor の SQLite データベースがここに置かれます。バックアップ/移行/トラブルシューティングを行う際、最初にこのディレクトリを特定できれば、基本的に権威あるデータソースを見つけることができます。</p><h2 id="学習後にできること" tabindex="-1">学習後にできること <a class="header-anchor" href="#学習後にできること" aria-label="Permalink to &quot;学習後にできること&quot;">​</a></h2><ul><li>Antigravity Tools のデータディレクトリがどこにあるかを知る（ワンクリックで開ける）</li><li>どのファイルをバックアップすべきか、どれがログ/キャッシュかを明確にする</li><li>トラブルシューティングが必要な場合、ログと監視データベースを迅速に特定できる</li><li>「ウィンドウを閉じる」と「プログラムを終了する」の違いを理解する（トレイ常駐）</li><li>2 種類の自動起動を区別する：起動時自動起動 vs リバースプロキシ自動起動</li></ul><h2 id="現在の課題" tabindex="-1">現在の課題 <a class="header-anchor" href="#現在の課題" aria-label="Permalink to &quot;現在の課題&quot;">​</a></h2><ul><li>バックアップ/移行したいが、アカウントが実際にどこに保存されているかわからない</li><li>UI エラー/リバースプロキシ呼び出し失敗だが、ログが見つからない</li><li>ウィンドウを閉じ、プログラムが終了したと思っていたが、まだバックグラウンドで実行されている</li></ul><h2 id="いつこの方法を使用するか" tabindex="-1">いつこの方法を使用するか <a class="header-anchor" href="#いつこの方法を使用するか" aria-label="Permalink to &quot;いつこの方法を使用するか&quot;">​</a></h2><ul><li>Antigravity Tools をインストールしたばかりで、「データがどこにあるか」を確認したい場合</li><li>マシン変更/システム再インストールを準備しており、アカウントと統計データを最初にバックアップしたい場合</li><li>OAuth 失敗、クォータ更新失敗、リバースプロキシ起動失敗、呼び出し 401/429 をトラブルシューティングする必要がある場合</li></ul><h2 id="🎒-開始前の準備" tabindex="-1">🎒 開始前の準備 <a class="header-anchor" href="#🎒-開始前の準備" aria-label="Permalink to &quot;🎒 開始前の準備&quot;">​</a></h2><ul><li>Antigravity Tools をインストールし、開くことができる</li><li>Settings ページに入れる（右上/サイドバーの設定入口）</li><li>システムアカウントが自分の Home ディレクトリにアクセスする権限を持っている</li></ul><div class="warning custom-block"><p class="custom-block-title">注意</p><p>このレッスンはどのファイルが「真のデータ」かを教えますが、これらのファイルを手動で編集することは推奨しません。設定を変更する場合は、優先的に UI で変更してください。</p></div><h2 id="コアアイデア" tabindex="-1">コアアイデア <a class="header-anchor" href="#コアアイデア" aria-label="Permalink to &quot;コアアイデア&quot;">​</a></h2><p>まず 1 文を覚えてください：</p><p>&quot;<strong>データディレクトリはローカル状態の単一の真実情報源であり、ログはトラブルシューティングの最初の入り口です。</strong>&quot;</p><p>Antigravity Tools は Home ディレクトリの下に <code>.antigravity_tools</code> データディレクトリを作成し、アカウント、ログ、統計ライブラリなどをそこに置きます（ディレクトリが存在しない場合は自動的に作成されます）。</p><p>同時に、デフォルトでトレイを有効にします。ウィンドウを閉じると、プログラムはすぐには終了せず、トレイに隠れてバックグラウンドで実行を続けます。</p><h2 id="手順に従って進める" tabindex="-1">手順に従って進める <a class="header-anchor" href="#手順に従って進める" aria-label="Permalink to &quot;手順に従って進める&quot;">​</a></h2><h3 id="ステップ-1-設定ページでデータディレクトリを開く" tabindex="-1">ステップ 1：設定ページでデータディレクトリを開く <a class="header-anchor" href="#ステップ-1-設定ページでデータディレクトリを開く" aria-label="Permalink to &quot;ステップ 1：設定ページでデータディレクトリを開く&quot;">​</a></h3><p><strong>なぜ</strong> まずデータディレクトリを正確に特定すれば、後でバックアップでもトラブルシューティングでも「着地点」があります。</p><p>Antigravity Tools で Settings を開き、Advanced に切り替えます。</p><p>「データディレクトリ」という読み取り専用入力ボックスが表示され（実際のパスを表示）、隣に開くボタンがあります。</p><p>開くボタンをクリックします。</p><p><strong>次のように表示されます</strong>：システムファイルマネージャがディレクトリを開き、パスは <code>~/.antigravity_tools/</code> のようになります。</p><h3 id="ステップ-2-データディレクトリパスを確認する-クロスシステム" tabindex="-1">ステップ 2：データディレクトリパスを確認する（クロスシステム） <a class="header-anchor" href="#ステップ-2-データディレクトリパスを確認する-クロスシステム" aria-label="Permalink to &quot;ステップ 2：データディレクトリパスを確認する（クロスシステム）&quot;">​</a></h3><p><strong>なぜ</strong> 後でバックアップスクリプトを書いたり、コマンドラインでトラブルシューティングしたりする際、システム上の実際のパスを知る必要があります。</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-au0nQ" id="tab-m3dKYAh" checked><label data-title="macOS/Linux" for="tab-m3dKYAh">macOS/Linux</label><input type="radio" name="group-au0nQ" id="tab-qVwbRYJ"><label data-title="Windows" for="tab-qVwbRYJ">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$dataDir </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$dataDir</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force $dataDir</span></span></code></pre></div></div></div><p><strong>次のように表示されます</strong>：ディレクトリが存在します（初めて設定ページを開く場合、ディレクトリは自動的に作成されます）。</p><h3 id="ステップ-3-データディレクトリ内の「重要なファイル」を認識する" tabindex="-1">ステップ 3：データディレクトリ内の「重要なファイル」を認識する <a class="header-anchor" href="#ステップ-3-データディレクトリ内の「重要なファイル」を認識する" aria-label="Permalink to &quot;ステップ 3：データディレクトリ内の「重要なファイル」を認識する&quot;">​</a></h3><p><strong>なぜ</strong> すべてのファイルがバックアップに値するわけではありません。まず「アカウントデータ」「統計ライブラリ/ログ」を明確に分けます。</p><p>次のファイル名はプロジェクトソースコードから来ており、すべて固定です：</p><table tabindex="0"><thead><tr><th>表示される内容</th><th>用途</th><th>関心を持つべきこと</th></tr></thead><tbody><tr><td><code>accounts.json</code></td><td>アカウントインデックス（アカウントリスト/現在のアカウントを含む）</td><td>アカウント移行時、一緒にバックアップすることを推奨</td></tr><tr><td><code>accounts/</code></td><td>各アカウントごとに 1 つの <code>*.json</code> ファイル</td><td>これがアカウントデータの本体</td></tr><tr><td><code>logs/</code></td><td>アプリケーションログディレクトリ</td><td>トラブルシューティングはまずここを見る</td></tr><tr><td><code>token_stats.db</code></td><td>Token Stats の SQLite データベース</td><td>Token Stats ページで見るデータはここから来る</td></tr><tr><td><code>proxy_logs.db</code></td><td>Proxy Monitor の SQLite データベース</td><td>Monitor ページで見るリクエストログはここから来る</td></tr><tr><td><code>warmup_history.json</code></td><td>Smart Warmup のローカル履歴記録</td><td>主に重複 warmup を避けるために使用</td></tr><tr><td><code>update_settings.json</code></td><td>更新チェック設定（自動チェック/間隔など）</td><td>通常、手動で変更する必要はない</td></tr></tbody></table><p><strong>次のように表示されます</strong>：少なくとも <code>logs/</code> ディレクトリがあります。まだアカウントを追加していない場合、<code>accounts.json</code>/<code>accounts/</code> はまだ表示されない場合があります。</p><h3 id="ステップ-4-ログの位置を記憶する-トラブルシューティングはこれに依存" tabindex="-1">ステップ 4：ログの位置を記憶する（トラブルシューティングはこれに依存） <a class="header-anchor" href="#ステップ-4-ログの位置を記憶する-トラブルシューティングはこれに依存" aria-label="Permalink to &quot;ステップ 4：ログの位置を記憶する（トラブルシューティングはこれに依存）&quot;">​</a></h3><p><strong>なぜ</strong> UI のエラー通知は通常「現象」しか与えず、実際の失敗原因（リクエスト失敗、ファイル読み書き失敗など）は多くの場合ログにあります。</p><p>Antigravity Tools はデータディレクトリの下の <code>logs/</code> にログを書き込みます。</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-gS8n1" id="tab-vijsOyc" checked><label data-title="macOS/Linux" for="tab-vijsOyc">macOS/Linux</label><input type="radio" name="group-gS8n1" id="tab-TEZToi2"><label data-title="Windows" for="tab-TEZToi2">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools/logs&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools\\logs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></div></div><p><strong>次のように表示されます</strong>：ディレクトリの下に日付ごとのローテーションログファイル（ファイル名は <code>app.log</code> で始まる）が存在します。</p><h3 id="ステップ-5-「ログをクリア」する必要がある場合、設定ページのワンクリッククリアを使用する" tabindex="-1">ステップ 5：「ログをクリア」する必要がある場合、設定ページのワンクリッククリアを使用する <a class="header-anchor" href="#ステップ-5-「ログをクリア」する必要がある場合、設定ページのワンクリッククリアを使用する" aria-label="Permalink to &quot;ステップ 5：「ログをクリア」する必要がある場合、設定ページのワンクリッククリアを使用する&quot;">​</a></h3><p><strong>なぜ</strong> 一部の問題は一度だけ再現し、その時のログを単独で残したい場合、最初にログをクリアすると比較しやすくなります。</p><p>Settings -&gt; Advanced でログ領域を見つけ、「Clear Logs」をクリックします。</p><p><strong>次のように表示されます</strong>：確認ボックスが表示されます。確認後、クリア成功が通知されます。</p><div class="tip custom-block"><p class="custom-block-title">心配する 2 つのこと</p><ul><li>ログは自動的に「日次ローテーション」を行い、起動時に 7 日を超える古いログをクリアしようとします。</li><li>「Clear Logs」はログファイルを 0 バイトに切り詰め、実行中のプロセスが同じファイルハンドルに書き続けられるようにします。</li></ul></div><h3 id="ステップ-6-「ウィンドウを閉じる」と「プログラムを終了する」の違いを明確にする-トレイ" tabindex="-1">ステップ 6：「ウィンドウを閉じる」と「プログラムを終了する」の違いを明確にする（トレイ） <a class="header-anchor" href="#ステップ-6-「ウィンドウを閉じる」と「プログラムを終了する」の違いを明確にする-トレイ" aria-label="Permalink to &quot;ステップ 6：「ウィンドウを閉じる」と「プログラムを終了する」の違いを明確にする（トレイ）&quot;">​</a></h3><p><strong>なぜ</strong> Antigravity Tools はデフォルトでトレイを有効にします。ウィンドウ右上の閉じるをクリックすると、プログラムはトレイに隠れて実行を続けます。終了したと思っていると、「ポートまだ占用中/バックグラウンドまだ実行中」の錯覚が起こりやすくなります。</p><p>この小さなフローで確認できます：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>操作：ウィンドウを閉じる（終了ではない）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  ステップ 1                ステップ 2                             │</span></span>
<span class="line"><span>│  ウィンドウ閉じる       →   システムトレイ/メニューバーでアイコンを探す              │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>次のように表示されます：トレイアイコンがまだ存在し、クリックするとウィンドウを再表示できます。</span></span></code></pre></div><p>トレイメニューには他にも 2 つのよく使うアクションがあります（UI を通さない場合に便利）：</p><ul><li>アカウント切り替え：次のアカウントに切り替える</li><li>クォータ更新：現在のアカウントクォータを更新（同時にフロントエンド表示更新を通知）</li></ul><h3 id="ステップ-7-起動時自動起動を設定する-起動後自動最小化" tabindex="-1">ステップ 7：起動時自動起動を設定する（起動後自動最小化） <a class="header-anchor" href="#ステップ-7-起動時自動起動を設定する-起動後自動最小化" aria-label="Permalink to &quot;ステップ 7：起動時自動起動を設定する（起動後自動最小化）&quot;">​</a></h3><p><strong>なぜ</strong> 「常駐サービス」のように動作させたい場合（トレイ常駐 + バックグラウンド更新）、起動時自動起動は毎回手動で開く手間を省けます。</p><p>Settings -&gt; General で「Auto Launch on Startup」を見つけ、有効にします。</p><p><strong>次のように表示されます</strong>：切り替え後、有効成功が通知されます。次回起動時、<code>--minimized</code> パラメータを付けて実行されます。</p><div class="info custom-block"><p class="custom-block-title">2 種類の「自動起動」、混同しないでください</p><table tabindex="0"><thead><tr><th>名称</th><th>指すもの</th><th>証拠</th></tr></thead><tbody><tr><td>起動時自動起動</td><td>コンピュータ起動後、Antigravity Tools を自動起動（デスクトップアプリ自体）</td><td>起動パラメータに <code>--minimized</code> が含まれ、<code>toggle_auto_launch</code> コマンドを提供</td></tr><tr><td>リバースプロキシ自動起動</td><td>Antigravity Tools 起動後、<code>proxy.auto_start=true</code> を設定すると、自動的にローカルリバースプロキシサービスを起動しようとする</td><td>アプリ起動時に設定を読み取り、<code>start_proxy_service(...)</code></td></tr></tbody></table></div><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><ul><li>[ ] Settings -&gt; Advanced でデータディレクトリの実際のパスが見えます</li><li>[ ] データディレクトリを開き、<code>accounts.json</code>、<code>accounts/</code>、<code>logs/</code>、<code>token_stats.db</code>、<code>proxy_logs.db</code> を大まかに認識できます</li><li>[ ] ログが <code>logs/</code> にあることを知り、コマンドラインで素早く見ることができます</li><li>[ ] ウィンドウを閉じた後もプログラムがトレイで実行中であることを知り、終了するにはトレイの Quit を使用することを知っています</li><li>[ ] 「起動時自動起動」と「リバースプロキシ自動起動」を区別できます</li></ul><h2 id="トラブルシューティング" tabindex="-1">トラブルシューティング <a class="header-anchor" href="#トラブルシューティング" aria-label="Permalink to &quot;トラブルシューティング&quot;">​</a></h2><table tabindex="0"><thead><tr><th>シナリオ</th><th>間違ったやり方（❌）</th><th>推奨されるやり方（✓）</th></tr></thead><tbody><tr><td>データディレクトリが見つからない</td><td>システム内で App のインストールディレクトリを無秩序に検索する</td><td>直接 Settings -&gt; Advanced で「データディレクトリ」を確認し、ワンクリックで開く</td></tr><tr><td>ウィンドウを閉じて終了したと思った</td><td>ウィンドウを閉じた後、設定を変更/ポートを変更する</td><td>最初にトレイアイコンがまだ存在するか確認する。終了するにはトレイの Quit を使用する</td></tr><tr><td>ログが多すぎてトラブルシューティングできない</td><td>問題を再現しながら古いログをめくる</td><td>最初に「Clear Logs」を実行し、再び 1 回再現し、最後に今回のログファイルのみを見る</td></tr><tr><td>アカウントデータを変更したい</td><td><code>accounts/*.json</code> を手動で編集する</td><td>UI のインポート/エクスポート/移行フローを使用する（次の関連セクションで説明）</td></tr></tbody></table><h2 id="このレッスンのまとめ" tabindex="-1">このレッスンのまとめ <a class="header-anchor" href="#このレッスンのまとめ" aria-label="Permalink to &quot;このレッスンのまとめ&quot;">​</a></h2><ul><li>データディレクトリは Home の下の <code>.antigravity_tools</code> に固定されます（macOS/Linux では通常非表示ディレクトリ）、アカウント/ログ/統計ライブラリはすべてここにあります</li><li>ログディレクトリは <code>logs/</code> で、トラブルシューティングはまずここを見る。必要に応じて設定ページでワンクリッククリアできます</li><li>ウィンドウを閉じるとトレイに隠れて実行を続ける。完全に終了するにはトレイの Quit を使用する</li><li>自動起動には 2 種類あります：起動時自動起動（アプリ）とリバースプロキシ自動起動（Proxy）</li></ul><hr><h2 id="次のレッスン予告" tabindex="-1">次のレッスン予告 <a class="header-anchor" href="#次のレッスン予告" aria-label="Permalink to &quot;次のレッスン予告&quot;">​</a></h2><blockquote><p>次のレッスンでは、<strong><a href="./../add-account/">アカウント追加：OAuth/Refresh Token デュアルチャンネルとベストプラクティス</a></strong> を学びます。</p></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を表示</strong></summary><blockquote><p>更新日時：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>データディレクトリの位置（<code>~/.antigravity_tools</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L16-L33" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>16-33</td></tr><tr><td>アカウントインデックスとアカウントファイルディレクトリ（<code>accounts.json</code> / <code>accounts/</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L16-L46" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>16-46</td></tr><tr><td>ログディレクトリと日次ローテーション（<code>logs/</code> + <code>app.log</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/logger.rs#L17-L83" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/logger.rs</code></a></td><td>17-83</td></tr><tr><td>ログのクリア（ファイル切り詰め）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/logger.rs#L149-L169" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/logger.rs</code></a></td><td>149-169</td></tr><tr><td>設定ページでデータディレクトリを表示 + ワンクリックで開く</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L525-L576" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>525-576</td></tr><tr><td>設定ページでワンクリックログクリア（ボタン + ダイアログロジック）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L127-L135" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>127-135</td></tr><tr><td>設定ページでワンクリックログクリア（Advanced タブボタン）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L732-L747" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>732-747</td></tr><tr><td>トレイメニューとクリックイベント（アカウント切り替え/更新/表示/終了）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/tray.rs#L9-L158" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/tray.rs</code></a></td><td>9-158</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>起動時自動起動スイッチ（<code>toggle_auto_launch</code> / <code>is_auto_launch_enabled</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/autostart.rs#L4-L39" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/autostart.rs</code></a></td><td>4-39</td></tr><tr><td>データディレクトリをワンクリックで開く / パスを取得 / ログクリアコマンド</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L578-L621" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>578-621</td></tr><tr><td>Token Stats データベースファイル名（<code>token_stats.db</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L58-L61" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>58-61</td></tr><tr><td>Proxy Monitor データベースファイル名（<code>proxy_logs.db</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/proxy_db.rs#L5-L8" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/proxy_db.rs</code></a></td><td>5-8</td></tr><tr><td>Warmup 履歴ファイル名（<code>warmup_history.json</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/scheduler.rs#L14-L17" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/scheduler.rs</code></a></td><td>14-17</td></tr><tr><td>更新設定ファイル名（<code>update_settings.json</code>）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/update_checker.rs#L150-L177" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/update_checker.rs</code></a></td><td>150-177</td></tr><tr><td>リバースプロキシ自動起動（<code>proxy.auto_start=true</code> 時にサービスを起動）</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/lib.rs#L107-L126" target="_blank" rel="noreferrer"><code>src-tauri/src/lib.rs</code></a></td><td>107-126</td></tr></tbody></table></details><h2 id="次のレッスン予告-1" tabindex="-1">次のレッスン予告 <a class="header-anchor" href="#次のレッスン予告-1" aria-label="Permalink to &quot;次のレッスン予告&quot;">​</a></h2><blockquote><p>次のレッスンでは、<strong><a href="./../add-account/">アカウント追加：OAuth/Refresh Token デュアルチャンネルとベストプラクティス</a></strong> を学びます。</p><p>学びます：</p><ul><li>いつ OAuth を使用し、いつ refresh_token を直接使用するか</li><li>コールバック失敗と refresh_token が取得できない場合の対処方法</li><li>refresh_token を一括インポートしてアカウントプールを迅速に構築する方法</li></ul></blockquote>`,69)])])}const u=a(i,[["render",o]]);export{g as __pageData,u as default};
